import java.nio.file.StandardCopyOption;
import java.net.URL;
import java.net.URI;
import java.sql.SQLException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;

public class CourseDetailController {
    @FXML private Label courseTitleLabel;
    @FXML private Label courseMetaLabel;
    @FXML private Button openCoursePdfButton;
    @FXML private Label chapterCompletionLabel;
    @FXML private Label quizTitleLabel;
    @FXML private Label quizMetaLabel;
    @FXML private Label quizHintLabel;
    @FXML private Label quizStateBadge;
    @FXML private VBox chapterContainer;
    @FXML private Button startQuizButton;
    @FXML private VBox quizSection;
    @FXML private Label quizProgressLabel;
    @FXML private Label quizScoreLabel;
    @FXML private Label questionNavLabel;
    @FXML private VBox questionCardContainer;
    @FXML private Button prevQuestionButton;
    @FXML private Button nextQuestionButton;
    @FXML private Button finishQuizButton;
    @FXML private VBox resultCard;
    @FXML private Label resultTitleLabel;
    @FXML private Label resultScoreBadge;
    @FXML private Label resultSummaryLabel;
    @FXML private Label attemptInfoLabel;
    @FXML private VBox resultDetailsBox;
    @FXML private Button backButton;

    private final ChapterService chapterService = new ChapterService();
    private final QuizService quizService = new QuizService();
    private final QuestionService questionService = new QuestionService();
    private final AnswerService answerService = new AnswerService();
    private final QuizStatisticsService quizStatisticsService = new QuizStatisticsService();

    private final Map<Integer, Integer> selectedAnswerByQuestionId = new HashMap<>();
    private final Map<Integer, QuizAttemptState> attemptsByQuizId = new HashMap<>();

    private List<Chapter> chapters = new ArrayList<>();
    private final Map<Integer, Quiz> quizByChapterId = new LinkedHashMap<>();
    private List<Question> questions = new ArrayList<>();
    private List<Answer> answers = new ArrayList<>();

    private Chapter selectedChapter;
    private Quiz quiz;
    private Course course;
    private int currentQuestionIndex;

    @FXML
    public void initialize() {
        showQuizSection(false);
        resultCard.setVisible(false);
        resultCard.setManaged(false);

        chapterCompletionLabel.setText("0 / 0 chapitres valides");
        questionNavLabel.setText("Question 0 sur 0");
        quizProgressLabel.setText("0 / 0");
        quizMetaLabel.setText("Aucun quiz selectionne");
        quizHintLabel.setText("Selectionnez un chapitre pour commencer.");
        quizStateBadge.setText("EN ATTENTE");
        quizStateBadge.getStyleClass().setAll("status-badge", "status-pending");

        prevQuestionButton.setDisable(true);
        nextQuestionButton.setDisable(true);
        finishQuizButton.setDisable(true);
        quizScoreLabel.setText("Score: 0 / 0");
    }

    public void setCourse(Course course) {
        this.course = course;
        courseTitleLabel.setText(course != null && course.getTitle() != null ? course.getTitle() : "Cours");
        if (course != null) {
            courseMetaLabel.setText("Niveau: " + nullSafe(course.getDifficulty(), "N/A")
                    + " | Duree: " + course.getDuration() + " min"
                    + " | Score validation: " + Math.round(course.getValidationScore()) + "%");
        } else {
            courseMetaLabel.setText("Niveau: - | Duree: - | Score validation: -");
        }

        String pdfRef = course != null ? course.getContent() : null;
        if (pdfRef != null && !pdfRef.isBlank()) {
            openCoursePdfButton.setText("Telecharger le PDF du cours");
            openCoursePdfButton.setDisable(false);
        } else {
            openCoursePdfButton.setText("PDF du cours indisponible");
            openCoursePdfButton.setDisable(true);
        }
        loadCourseStructure();
    }

    @FXML
    private void onOpenCoursePdf() {
        if (course == null || course.getContent() == null || course.getContent().isBlank()) {
            showError("PDF", "Aucun PDF n'est renseigne pour ce cours.");
            return;
        }

        try {
            String pdfRef = course.getContent().trim();
            FileChooser fileChooser = new FileChooser();
            fileChooser.setTitle("Telecharger le PDF du cours");
            fileChooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("Fichiers PDF", "*.pdf"));
            fileChooser.setInitialFileName(buildPdfFileName());

            File targetFile = fileChooser.showSaveDialog(backButton.getScene() != null ? backButton.getScene().getWindow() : null);
            if (targetFile == null) {
                return;
            }

            if (pdfRef.startsWith("http://") || pdfRef.startsWith("https://")) {
                try (InputStream inputStream = new URL(pdfRef).openStream()) {
                    Files.copy(inputStream, targetFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
                }
            } else {
                File pdfFile = new File(pdfRef);
                if (!pdfFile.exists()) {
                    showError("PDF", "Fichier introuvable: " + pdfRef);
                    return;
                }
                Files.copy(pdfFile.toPath(), targetFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
            }

            showInfo("PDF", "PDF telecharge vers: " + targetFile.getAbsolutePath());
        } catch (Exception e) {
            showError("PDF", "Impossible de telecharger le PDF du cours.");
        }
    }

    @FXML
    private void onBack() {
        Scene scene = backButton.getScene();
        if (scene != null) {
            Object marker = scene.getRoot() != null ? scene.getRoot().getUserData() : null;
            Window window = scene.getWindow();
            if ("course-detail-window".equals(marker) && window != null) {
                window.hide();
                return;
            }
        }

        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/Fxml/client/base.fxml"));
            Parent root = loader.load();
            BaseController controller = loader.getController();
            controller.loadCourses();

            if (scene != null) {
                scene.setRoot(root);
            }
        } catch (IOException e) {
            showError("Navigation", "Impossible de revenir a la liste des cours.");
        }
    }

    @FXML
    private void onStartQuiz() {
        openSelectedQuizWindow();
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/Fxml/client/base.fxml"));
            Parent root = loader.load();
            BaseController controller = loader.getController();
            controller.loadCourses();

            Scene scene = backButton.getScene();
            if (scene != null) {
                scene.setRoot(root);
            }
        } catch (IOException e) {
            showError("Navigation", "Impossible de revenir a la liste des cours.");
        }
    }

    @FXML
    private void onFinishQuiz() {
        if (quiz == null || questions.isEmpty()) {
            return;
        }

        int unanswered = questions.size() - selectedAnswerByQuestionId.size();
        if (unanswered > 0) {
            Alert confirm = new Alert(AlertType.CONFIRMATION);
            confirm.setTitle("Soumettre le quiz");
            confirm.setHeaderText("Questions non repondues: " + unanswered);
            confirm.setContentText("Voulez-vous terminer le quiz ? Les questions non repondues seront considerees incorrectes.");
            if (confirm.showAndWait().isEmpty() || confirm.getResult().getButtonData().isCancelButton()) {
                return;
            }
        }

        QuizComputation computation = computeQuizResult();
        int threshold = Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore());
        boolean passed = computation.percentage >= threshold;

        QuizAttemptState previous = attemptsByQuizId.get(quiz.getId());
        int currentAttempt = previous == null ? 1 : previous.attemptNumber + 1;

        try {
            currentAttempt = quizStatisticsService.saveQuizAttempt(quiz.getId(), null, computation.percentage);
        } catch (SQLException e) {
            showWarning("Sauvegarde quiz", "Tentative non enregistree en base: " + e.getMessage());
        }

        attemptsByQuizId.put(quiz.getId(), new QuizAttemptState(currentAttempt, computation.percentage, passed));

        applyResultState(computation, threshold, currentAttempt, passed);
        updateChapterProgressLabel();
        renderChapterCards();
        updateQuizHeader();

        Alert alert = new Alert(AlertType.INFORMATION);
        alert.setTitle("Resultat du quiz");
        alert.setHeaderText(passed ? "Quiz valide" : "Quiz non valide");
        alert.setContentText("Score: " + computation.earnedPoints + " / " + computation.totalPoints
                + " (" + computation.percentage + "%). Seuil requis: " + threshold + "%.");
        alert.showAndWait();
    }

    @FXML
    private void onPrevQuestion() {
        if (currentQuestionIndex > 0) {
            currentQuestionIndex--;
            renderCurrentQuestion();
        }
    }

    @FXML
    private void onNextQuestion() {
        if (currentQuestionIndex < questions.size() - 1) {
            currentQuestionIndex++;
            renderCurrentQuestion();
        }
    }

    private void loadCourseStructure() {
        selectedAnswerByQuestionId.clear();
        quiz = null;
        selectedChapter = null;
        chapters = new ArrayList<>();
        quizByChapterId.clear();
        questions = new ArrayList<>();
        answers = new ArrayList<>();

        showQuizSection(false);
        resultCard.setVisible(false);
        resultCard.setManaged(false);
        questionCardContainer.getChildren().clear();

        try {
            List<Chapter> allChapters = chapterService.findAll();
            List<Quiz> quizzes = quizService.findAll();

            if (course != null) {
                chapters = allChapters.stream()
                        .filter(chapter -> chapter.getCourse() != null && Objects.equals(chapter.getCourse().getId(), course.getId()))
                        .sorted(Comparator.comparingInt(Chapter::getChapterOrder))
                        .toList();

                List<Quiz> quizzesForCourse = quizzes.stream()
                        .filter(item -> item.getCourse() != null && Objects.equals(item.getCourse().getId(), course.getId()))
                        .toList();

                restoreAttemptHistory(quizzesForCourse);

                for (Chapter chapter : chapters) {
                    Quiz linkedQuiz = quizzesForCourse.stream()
                            .filter(item -> item.getChapter() != null && Objects.equals(item.getChapter().getId(), chapter.getId()))
                            .findFirst()
                            .orElse(null);
                    if (linkedQuiz != null) {
                        quizByChapterId.put(chapter.getId(), linkedQuiz);
                    }
                }

                if (quizByChapterId.isEmpty() && !quizzesForCourse.isEmpty()) {
                    quiz = quizzesForCourse.get(0);
                } else if (!chapters.isEmpty()) {
                    for (Chapter chapter : chapters) {
                        Quiz chapterQuiz = quizByChapterId.get(chapter.getId());
                        if (chapterQuiz != null) {
                            selectedChapter = chapter;
                            quiz = chapterQuiz;
                            break;
                        }
                    }
                }
            }

            renderChapterCards();
            updateChapterProgressLabel();

            if (quiz == null) {
                quizTitleLabel.setText("Aucun quiz disponible pour ce cours.");
                quizMetaLabel.setText("Le cours n'a pas encore de quiz associe.");
                quizHintLabel.setText("Ajoutez des quiz en backoffice pour activer cette section.");
                quizStateBadge.setText("SANS QUIZ");
                quizStateBadge.getStyleClass().setAll("status-badge", "status-danger");
                startQuizButton.setDisable(true);
                return;
            }

            updateQuizHeader();
            startQuizButton.setDisable(false);
        } catch (SQLException e) {
            quizTitleLabel.setText("Impossible de charger le quiz.");
            quizMetaLabel.setText("Erreur de chargement.");
            quizHintLabel.setText("Verifiez la connexion a la base de donnees.");
            quizStateBadge.setText("ERREUR");
            quizStateBadge.getStyleClass().setAll("status-badge", "status-danger");
            startQuizButton.setDisable(true);
            chapterContainer.getChildren().setAll(buildInlineHint("Impossible de charger les chapitres du cours."));
        }
    }

    private void renderCurrentQuestion() {
        if (questions.isEmpty()) {
            questionCardContainer.getChildren().setAll(new Label("Aucune question pour ce quiz."));
            quizProgressLabel.setText("0 / 0");
            questionNavLabel.setText("Question 0 sur 0");
            quizScoreLabel.setText("Score: 0 / 0");
            prevQuestionButton.setDisable(true);
            nextQuestionButton.setDisable(true);
            finishQuizButton.setDisable(true);
            return;
        }

        Question question = questions.get(currentQuestionIndex);
        quizProgressLabel.setText((currentQuestionIndex + 1) + " / " + questions.size());
        questionNavLabel.setText("Question " + (currentQuestionIndex + 1) + " sur " + questions.size());

        VBox questionCard = new VBox(12);
        questionCard.getStyleClass().add("question-block");

        Label questionLabel = new Label(question.getContent() == null ? "Sans contenu" : question.getContent());
        questionLabel.getStyleClass().add("question-title");
        questionLabel.setWrapText(true);
        questionCard.getChildren().add(questionLabel);

        VBox answersBox = new VBox(10);
        List<Answer> questionAnswers = answers.stream()
                .filter(answer -> answer.getQuestion() != null && Objects.equals(answer.getQuestion().getId(), question.getId()))
                .toList();

        if (questionAnswers.isEmpty()) {
            answersBox.getChildren().add(new Label("Aucune reponse configuree."));
        } else {
            Integer selectedAnswerId = selectedAnswerByQuestionId.get(question.getId());
            for (Answer answer : questionAnswers) {
                Button answerButton = new Button(answer.getContent() == null ? "Sans contenu" : answer.getContent());
                answerButton.getStyleClass().add("quiz-answer-option");
                answerButton.setMaxWidth(Double.MAX_VALUE);

                if (selectedAnswerId != null && Objects.equals(selectedAnswerId, answer.getId())) {
                    answerButton.getStyleClass().add("selected");
                }

                answerButton.setOnAction(event -> {
                    selectedAnswerByQuestionId.put(question.getId(), answer.getId());
                    updateScoreLabel();
                    renderCurrentQuestion();
                });
                answersBox.getChildren().add(answerButton);
            }
        }

        questionCard.getChildren().add(answersBox);
        questionCardContainer.getChildren().setAll(questionCard);
        prevQuestionButton.setDisable(currentQuestionIndex == 0);
        nextQuestionButton.setDisable(currentQuestionIndex >= questions.size() - 1);
        finishQuizButton.setDisable(false);
    }

    private void updateScoreLabel() {
        quizScoreLabel.setText("Score: " + computeScore() + " / " + questions.size());
    }

    private int computeScore() {
        int score = 0;
        for (Question question : questions) {
            Integer selectedAnswerId = selectedAnswerByQuestionId.get(question.getId());
            if (selectedAnswerId == null) {
                continue;
            }
            boolean good = answers.stream()
                    .anyMatch(answer -> answer.getQuestion() != null
                            && Objects.equals(answer.getQuestion().getId(), question.getId())
                            && answer.isCorrect()
                            && Objects.equals(answer.getId(), selectedAnswerId));
            if (good) {
                score++;
            }
        }
        return score;
    }

    private QuizComputation computeQuizResult() {
        int totalPoints = 0;
        int earnedPoints = 0;
        for (Question question : questions) {
            int questionPoints = Math.max(1, Math.round(question.getPoint()));
            totalPoints += questionPoints;

            Integer selectedAnswerId = selectedAnswerByQuestionId.get(question.getId());
            boolean isCorrect = selectedAnswerId != null && answers.stream()
                    .anyMatch(answer -> answer.getQuestion() != null
                            && Objects.equals(answer.getQuestion().getId(), question.getId())
                            && answer.isCorrect()
                            && Objects.equals(answer.getId(), selectedAnswerId));

            if (isCorrect) {
                earnedPoints += questionPoints;
            }
        }

        int percentage = totalPoints == 0 ? 0 : Math.round((earnedPoints * 100f) / totalPoints);
        return new QuizComputation(totalPoints, earnedPoints, percentage);
    }

    private void applyResultState(QuizComputation computation, int threshold, int attemptNumber, boolean passed) {
        resultCard.setVisible(true);
        resultCard.setManaged(true);

        resultTitleLabel.setText(passed ? "Quiz valide" : "Quiz non valide");
        resultSummaryLabel.setText(passed
                ? "Excellent travail. Le chapitre est marque comme complete."
                : "Vous pouvez recommencer pour atteindre le score minimal.");
        resultScoreBadge.setText(computation.percentage + "%");
        resultScoreBadge.getStyleClass().setAll("result-score-badge", passed ? "success" : "fail");

        attemptInfoLabel.setText("Tentative " + attemptNumber + " | Seuil: " + threshold + "% | Points: "
                + computation.earnedPoints + " / " + computation.totalPoints);

        renderResultDetails();
    }

    private void renderResultDetails() {
        resultDetailsBox.getChildren().clear();

        for (Question question : questions) {
            VBox line = new VBox(6);
            line.getStyleClass().add("result-line");

            HBox header = new HBox(8);
            header.setAlignment(Pos.CENTER_LEFT);
            Label qLabel = new Label(question.getContent() == null ? "Question" : question.getContent());
            qLabel.getStyleClass().add("result-question");

            Region spacer = new Region();
            HBox.setHgrow(spacer, Priority.ALWAYS);

            Integer selectedAnswerId = selectedAnswerByQuestionId.get(question.getId());
            boolean good = selectedAnswerId != null && answers.stream()
                    .anyMatch(answer -> answer.getQuestion() != null
                            && Objects.equals(answer.getQuestion().getId(), question.getId())
                            && answer.isCorrect()
                            && Objects.equals(answer.getId(), selectedAnswerId));

            Label state = new Label(good ? "Correct" : "Incorrect");
            state.getStyleClass().setAll("mini-pill", good ? "mini-success" : "mini-danger");

            header.getChildren().addAll(qLabel, spacer, state);

            String selectedAnswerText = answers.stream()
                    .filter(answer -> Objects.equals(answer.getId(), selectedAnswerId))
                    .map(Answer::getContent)
                    .findFirst()
                    .orElse("Non repondu");
            Label selectedLabel = new Label("Votre reponse: " + selectedAnswerText);
            selectedLabel.getStyleClass().add("result-subline");

                line.getChildren().addAll(header, selectedLabel);
            resultDetailsBox.getChildren().add(line);
        }
    }

    private void renderChapterCards() {
        chapterContainer.getChildren().clear();

        if (chapters == null || chapters.isEmpty()) {
            chapterContainer.getChildren().add(buildInlineHint("Aucun chapitre configure pour ce cours."));
            return;
        }

        for (Chapter chapter : chapters) {
            chapterContainer.getChildren().add(buildChapterCard(chapter));
        }
    }

    private VBox buildChapterCard(Chapter chapter) {
        VBox card = new VBox(10);
        card.getStyleClass().add("chapter-item-card");
        card.setPadding(new Insets(14));

        HBox header = new HBox(10);
        header.setAlignment(Pos.CENTER_LEFT);

        Label order = new Label(String.valueOf(chapter.getChapterOrder()));
        order.getStyleClass().add("chapter-order-pill");

        VBox textWrap = new VBox(4);
        Label title = new Label(chapter.getTitle() == null ? "Chapitre" : chapter.getTitle());
        title.getStyleClass().add("chapter-item-title");
        Label excerpt = new Label(truncate(chapter.getContent(), 120));
        excerpt.getStyleClass().add("chapter-item-excerpt");
        excerpt.setWrapText(true);
        textWrap.getChildren().addAll(title, excerpt);

        Region spacer = new Region();
        HBox.setHgrow(spacer, Priority.ALWAYS);

        Quiz chapterQuiz = quizByChapterId.get(chapter.getId());
        Label badge = new Label();
        if (chapterQuiz == null) {
            badge.setText("Sans quiz");
            badge.getStyleClass().setAll("mini-pill", "mini-neutral");
        } else {
            QuizAttemptState state = attemptsByQuizId.get(chapterQuiz.getId());
            if (state != null && state.passed) {
                badge.setText(state.scorePercent + "% - Valide");
                badge.getStyleClass().setAll("mini-pill", "mini-success");
            } else if (state != null) {
                badge.setText("A refaire " + state.scorePercent + "%");
                badge.getStyleClass().setAll("mini-pill", "mini-danger");
            } else {
                badge.setText("A faire");
                badge.getStyleClass().setAll("mini-pill", "mini-warning");
            }
        }

        header.getChildren().addAll(order, textWrap, spacer, badge);

        if (chapterQuiz != null) {
            Button openQuiz = new Button("Ouvrir session quiz");
            openQuiz.getStyleClass().setAll("courses-action-btn", "secondary");
            openQuiz.setOnAction(event -> {
                selectedChapter = chapter;
                quiz = chapterQuiz;
                updateQuizHeader();
                startQuizButton.setDisable(false);
                openSelectedQuizWindow();
            });
            card.getChildren().addAll(header, openQuiz);
        } else {
            card.getChildren().add(header);
        }

        return card;
    }

    private Label buildInlineHint(String text) {
        Label hint = new Label(text);
        hint.getStyleClass().add("course-empty-subtitle");
        return hint;
    }

    private void updateQuizHeader() {
        quizTitleLabel.setText("Quiz: " + (quiz.getTitle() == null ? "Sans titre" : quiz.getTitle()));

        int questionCount = countQuizQuestions(quiz.getId());
        int attempts = quiz.getMaxAttempts() <= 0 ? 3 : quiz.getMaxAttempts();
        int passing = Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore());
        quizMetaLabel.setText(questionCount + " questions | " + attempts + " tentatives max | score requis " + passing + "%");

        if (selectedChapter != null && selectedChapter.getTitle() != null) {
            quizHintLabel.setText("Chapitre: " + selectedChapter.getTitle());
        } else {
            quizHintLabel.setText("Quiz global du cours");
        }

        QuizAttemptState state = attemptsByQuizId.get(quiz.getId());
        if (state == null) {
            quizStateBadge.setText("NOUVEAU");
            quizStateBadge.getStyleClass().setAll("status-badge", "status-pending");
            return;
        }
        if (state.passed) {
            quizStateBadge.setText(state.scorePercent + "% - VALIDE");
            quizStateBadge.getStyleClass().setAll("status-badge", "status-success");
        } else {
            quizStateBadge.setText("A REFAIRE " + state.scorePercent + "%");
            quizStateBadge.getStyleClass().setAll("status-badge", "status-danger");
        }
    }

    private int countQuizQuestions(Integer quizId) {
        if (quizId == null) {
            return 0;
        }
        if (questions != null && !questions.isEmpty() && questions.get(0).getQuiz() != null
                && Objects.equals(questions.get(0).getQuiz().getId(), quizId)) {
            return questions.size();
        }
        try {
            return (int) questionService.findAll().stream()
                    .filter(item -> item.getQuiz() != null && Objects.equals(item.getQuiz().getId(), quizId))
                    .count();
        } catch (SQLException e) {
            return 0;
        }
    }

    private void updateChapterProgressLabel() {
        if (chapters == null || chapters.isEmpty()) {
            chapterCompletionLabel.setText("0 / 0 chapitres valides");
            return;
        }

        int quizChapters = 0;
        int completed = 0;
        for (Chapter chapter : chapters) {
            Quiz chapterQuiz = quizByChapterId.get(chapter.getId());
            if (chapterQuiz == null) {
                continue;
            }
            quizChapters++;
            QuizAttemptState state = attemptsByQuizId.get(chapterQuiz.getId());
            if (state != null && state.passed) {
                completed++;
            }
        }
        chapterCompletionLabel.setText(completed + " / " + quizChapters + " chapitres valides");
    }

    private void restoreAttemptHistory(List<Quiz> quizzesForCourse) {
        if (quizzesForCourse == null || quizzesForCourse.isEmpty()) {
            return;
        }

        for (Quiz courseQuiz : quizzesForCourse) {
            if (courseQuiz.getId() == null) {
                continue;
            }

            try {
                List<QuizAttemptDetail> attempts = quizStatisticsService.findAttemptsForQuiz(
                        courseQuiz.getId(),
                        courseQuiz.getPassingScore()
                );

                // Chercher la tentative réussie
                QuizAttemptDetail passedAttempt = attempts.stream()
                        .filter(QuizAttemptDetail::isPassed)
                        .findFirst()
                        .orElse(null);

                if (passedAttempt != null) {
                    attemptsByQuizId.put(courseQuiz.getId(), new QuizAttemptState(
                            passedAttempt.getAttemptNumber(),
                            (int) Math.round(passedAttempt.getScore()),
                            true
                    ));
                } else if (!attempts.isEmpty()) {
                    // Si aucune réussite, prendre le meilleur score
                    QuizAttemptDetail bestAttempt = attempts.stream()
                            .max(Comparator.comparingDouble(QuizAttemptDetail::getScore))
                            .orElse(null);

                    if (bestAttempt != null) {
                        attemptsByQuizId.put(courseQuiz.getId(), new QuizAttemptState(
                                bestAttempt.getAttemptNumber(),
                                (int) Math.round(bestAttempt.getScore()),
                                false
                        ));
                    }
                }
            } catch (SQLException e) {
                System.err.println("Unable to restore quiz history for quiz " + courseQuiz.getId() + ": " + e.getMessage());
            }
        }
    }

    private String buildPdfFileName() {
        String baseName = course != null && course.getTitle() != null && !course.getTitle().isBlank()
                ? course.getTitle().trim()
                : "cours";
        baseName = baseName.replaceAll("[\\\\/:*?\"<>|]", "_");
        if (!baseName.toLowerCase().endsWith(".pdf")) {
            baseName += ".pdf";
        }
        return baseName;
    }

    private void showInfo(String title, String message) {
        Alert alert = new Alert(AlertType.INFORMATION, message, ButtonType.OK);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    private String truncate(String value, int maxLength) {
        if (value == null || value.isBlank()) {
            return "Aucun contenu detaille.";
        }
        String normalized = value.replace('\n', ' ').trim();
        if (normalized.length() <= maxLength) {
            return normalized;
        }
        return normalized.substring(0, Math.max(0, maxLength - 3)) + "...";
    }

    private String nullSafe(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }

    private void showQuizSection(boolean visible) {
        quizSection.setVisible(visible);
        quizSection.setManaged(visible);
    }

    private void showError(String title, String message) {
        Alert alert = new Alert(AlertType.ERROR, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    private void openSelectedQuizWindow() {
        if (quiz == null) {
            showWarning("Quiz", "Aucun quiz disponible pour ce chapitre.");
            return;
        }

        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource("/Fxml/client/QuizSessionView.fxml"));
            Parent root = loader.load();
            QuizSessionController controller = loader.getController();
            controller.setQuizContext(quiz, selectedChapter != null ? selectedChapter.getTitle() : "Quiz du cours");

            Stage stage = new Stage();
            stage.setTitle("Session Quiz - " + (quiz.getTitle() == null ? "Quiz" : quiz.getTitle()));
            stage.setScene(new Scene(root, 1080, 820));
            stage.setMinWidth(980);
            stage.setMinHeight(760);
            if (backButton.getScene() != null && backButton.getScene().getWindow() != null) {
                stage.initOwner(backButton.getScene().getWindow());
            }
            stage.centerOnScreen();
            stage.show();
        } catch (IOException e) {
            showError("Quiz", "Impossible d'ouvrir la fenetre du quiz.");
        }
    }

    private void showWarning(String title, String message) {
        Alert alert = new Alert(AlertType.WARNING, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    private record QuizAttemptState(int attemptNumber, int scorePercent, boolean passed) {
    }

    private record QuizComputation(int totalPoints, int earnedPoints, int percentage) {
    }
}

package com.pidev.Controllers.client;

import com.pidev.Services.AnswerService;
import com.pidev.Services.QuestionService;
import com.pidev.Services.QuizStatisticsService;
import com.pidev.models.Answer;
import com.pidev.models.Question;
import com.pidev.models.Quiz;
import javafx.fxml.FXML;
import javafx.geometry.Pos;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.ProgressBar;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.animation.KeyFrame;
import javafx.animation.Timeline;
import javafx.util.Duration;
import javafx.stage.Window;
import javafx.application.Platform;
import javafx.scene.Node;
import java.util.concurrent.CompletableFuture;
import com.pidev.Services.AiFeedbackService;
import com.pidev.Services.TranslationService;
import com.pidev.Services.CertificateGeneratorService;
import javafx.stage.FileChooser;
import java.io.File;
import java.awt.Desktop;

import java.sql.SQLException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;

public class QuizSessionController {

    @FXML private Label quizTitleLabel;
    @FXML private Label quizContextLabel;
    @FXML private Label questionCountLabel;
    @FXML private Label attemptLabel;
    @FXML private Label requiredScoreLabel;
    @FXML private Label timeLimitLabel;

    @FXML private VBox introSection;
    @FXML private VBox questionSection;
    @FXML private VBox resultSection;

    @FXML private Label questionNavLabel;
    @FXML private Label answeredCounterLabel;
    @FXML private Label liveScoreLabel;
    @FXML private ProgressBar questionProgressBar;
    @FXML private Label timerBadgeLabel;
    @FXML private Label questionTextLabel;
    @FXML private Label questionFeedbackLabel;
    @FXML private VBox answersContainer;
    @FXML private HBox quickNavContainer;

    @FXML private Button prevButton;
    @FXML private Button nextButton;
    @FXML private Button finishButton;

    @FXML private Label resultTitleLabel;
    @FXML private Label resultSummaryLabel;
    @FXML private Label resultScoreLabel;
    @FXML private Label aiFeedbackLabel;
    @FXML private Button downloadCertButton;

    private final QuestionService questionService = new QuestionService();
    private final AnswerService answerService = new AnswerService();
    private final QuizStatisticsService quizStatisticsService = new QuizStatisticsService();
    private final AiFeedbackService aiFeedbackService = new AiFeedbackService();
    private final TranslationService translationService = new TranslationService();
    private final CertificateGeneratorService certificateGeneratorService = new CertificateGeneratorService();

    private final Map<Integer, Integer> selectedAnswerByQuestionId = new HashMap<>();
    private List<Question> questions = new ArrayList<>();
    private List<Answer> answers = new ArrayList<>();

    private Quiz quiz;
    private int currentQuestionIndex;
    private int remainingSeconds;
    private Timeline countdownTimeline;
    private boolean isTranslatedFr = false;

    @FXML
    public void initialize() {
        showSection(true, false, false);
        timerBadgeLabel.setText("Libre");
        if (answeredCounterLabel != null) {
            answeredCounterLabel.setText("0 / 0 repondues");
        }
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
    }

    public void setQuizContext(Quiz quiz, String chapterName) {
        this.quiz = quiz;
        String title = quiz != null && quiz.getTitle() != null ? quiz.getTitle() : "Quiz";
        quizTitleLabel.setText(title);
        quizContextLabel.setText(chapterName == null || chapterName.isBlank() ? "Quiz du cours" : chapterName);

        int attempts = quiz != null && quiz.getMaxAttempts() > 0 ? quiz.getMaxAttempts() : 3;
        int passing = quiz != null ? Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore()) : 70;
        int time = quiz != null ? quiz.getTimeLimit() : 0;

        attemptLabel.setText("1/" + attempts);
        requiredScoreLabel.setText(passing + "%");
        timeLimitLabel.setText(time <= 0 ? "Libre" : time + " min");
        remainingSeconds = Math.max(0, time) * 60;
        timerBadgeLabel.setText(time <= 0 ? "Libre" : formatTime(remainingSeconds));

        loadQuizData();
    }

    @FXML
    private void onStartQuiz() {
        if (questions.isEmpty()) {
            showError("Quiz", "Aucune question disponible pour ce quiz.");
            return;
        }
        selectedAnswerByQuestionId.clear();
        currentQuestionIndex = 0;
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
        startCountdown();
        showSection(false, true, false);
        renderCurrentQuestion();
    }

    @FXML
    private void onPrevQuestion() {
        if (currentQuestionIndex > 0) {
            currentQuestionIndex--;
            renderCurrentQuestion();
        }
    }

    @FXML
    private void onNextQuestion() {
        if (currentQuestionIndex < questions.size() - 1) {
            currentQuestionIndex++;
            renderCurrentQuestion();
        }
    }

    @FXML
    private void onFinishQuiz() {
        if (questions.isEmpty()) {
            return;
        }

        int unanswered = questions.size() - selectedAnswerByQuestionId.size();
        if (unanswered > 0) {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Soumettre le quiz");
            confirm.setHeaderText("Questions non repondues: " + unanswered);
            confirm.setContentText("Voulez-vous terminer le quiz maintenant ? Les questions non repondues seront comptees comme incorrectes.");
            if (confirm.showAndWait().isEmpty() || confirm.getResult().getButtonData().isCancelButton()) {
                return;
            }
        }

        stopCountdown();

        int total = questions.size();
        int score = computeScore();
        int percent = total == 0 ? 0 : Math.round(score * 100f / total);
        int passing = Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore());
        boolean passed = percent >= passing;
        int attemptNumber = 1;

        try {
            attemptNumber = quizStatisticsService.saveQuizAttempt(quiz.getId(), null, percent);
        } catch (SQLException e) {
            showError("Sauvegarde quiz", "Tentative non enregistree en base: " + e.getMessage());
        }

        resultTitleLabel.setText(passed ? "Quiz valide" : "Quiz non valide");
        resultSummaryLabel.setText(
                passed
                        ? "Bravo, vous avez atteint le score requis. Tentative " + attemptNumber + "."
                        : "Vous pouvez relancer le quiz pour améliorer votre resultat. Tentative " + attemptNumber + "."
        );
        resultScoreLabel.setText(score + " / " + total + " (" + percent + "%)");
        resultScoreLabel.getStyleClass().setAll("result-score-badge", passed ? "success" : "fail");

        if (!passed) {
            List<Question> failedQuestions = questions.stream()
                .filter(q -> {
                    Integer sel = selectedAnswerByQuestionId.get(q.getId());
                    return sel == null || answers.stream().noneMatch(a -> a.getQuestion() != null && Objects.equals(a.getQuestion().getId(), q.getId()) && a.isCorrect() && Objects.equals(a.getId(), sel));
                })
                .toList();
            String feedback = aiFeedbackService.generateFeedback(failedQuestions);
            aiFeedbackLabel.setText(feedback);
            aiFeedbackLabel.setVisible(true);
            aiFeedbackLabel.setManaged(true);
            if (downloadCertButton != null) {
                downloadCertButton.setVisible(false);
                downloadCertButton.setManaged(false);
            }
        } else {
            aiFeedbackLabel.setVisible(false);
            aiFeedbackLabel.setManaged(false);
            if (downloadCertButton != null) {
                downloadCertButton.setVisible(true);
                downloadCertButton.setManaged(true);
            }
        }

        showSection(false, false, true);
    }

    @FXML
    private void onCloseWindow() {
        Window window = quizTitleLabel.getScene() != null ? quizTitleLabel.getScene().getWindow() : null;
        if (window != null) {
            window.hide();
        }
    }

    @FXML
    private void onRetry() {
        onStartQuiz();
    }

    @FXML
    private void onDownloadCertificate() {
        FileChooser fileChooser = new FileChooser();
        fileChooser.setTitle("Enregistrer le certificat");
        fileChooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("Fichiers PDF", "*.pdf"));
        fileChooser.setInitialFileName("Certificat_" + (quiz != null && quiz.getTitle() != null ? quiz.getTitle().replaceAll("\\s+", "_") : "Quiz") + ".pdf");
        Window window = quizTitleLabel.getScene() != null ? quizTitleLabel.getScene().getWindow() : null;
        if (window == null) return;
        File file = fileChooser.showSaveDialog(window);

        if (file != null) {
            try {
                int total = questions.size();
                int score = computeScore();
                int percent = total == 0 ? 0 : Math.round(score * 100f / total);
                String courseName = quizContextLabel.getText();
                certificateGeneratorService.generateCertificate(file.getAbsolutePath(), "Étudiant", courseName, percent);

                Alert success = new Alert(Alert.AlertType.INFORMATION);
                success.setTitle("Succès");
                success.setHeaderText("Certificat généré avec succès !");
                success.setContentText("Le certificat a été sauvegardé dans : " + file.getAbsolutePath());
                success.showAndWait();

                try {
                    Desktop.getDesktop().open(file);
                } catch (Exception e) {
                    // Ignorer
                }
            } catch (Exception e) {
                showError("Erreur", "Impossible de générer le certificat : " + e.getMessage());
            }
        }
    }

    private void startCountdown() {
        stopCountdown();
        int timeLimitMinutes = quiz == null ? 0 : quiz.getTimeLimit();
        if (timeLimitMinutes <= 0) {
            timerBadgeLabel.setText("Libre");
            return;
        }

        remainingSeconds = timeLimitMinutes * 60;
        timerBadgeLabel.setText(formatTime(remainingSeconds));
        countdownTimeline = new Timeline(new KeyFrame(Duration.seconds(1), event -> {
            remainingSeconds--;
            timerBadgeLabel.setText(formatTime(Math.max(remainingSeconds, 0)));
            if (remainingSeconds <= 0) {
                stopCountdown();
                onFinishQuiz();
            }
        }));
        countdownTimeline.setCycleCount(Timeline.INDEFINITE);
        countdownTimeline.play();
    }

    private void stopCountdown() {
        if (countdownTimeline != null) {
            countdownTimeline.stop();
            countdownTimeline = null;
        }
    }

    private String formatTime(int seconds) {
        int safeSeconds = Math.max(0, seconds);
        int minutes = safeSeconds / 60;
        int rest = safeSeconds % 60;
        return String.format("%02d:%02d", minutes, rest);
    }

    private void loadQuizData() {
        try {
            List<Question> loadedQuestions = questionService.findAll().stream()
                    .filter(item -> item.getQuiz() != null && quiz != null && Objects.equals(item.getQuiz().getId(), quiz.getId()))
                    .sorted(Comparator.comparingInt(item -> item.getId() == null ? Integer.MAX_VALUE : item.getId()))
                    .toList();
            this.questions = new ArrayList<>(loadedQuestions);
            this.answers = answerService.findAll();
        } catch (SQLException e) {
            this.questions = new ArrayList<>();
            this.answers = new ArrayList<>();
            showError("Quiz", "Impossible de charger les questions du quiz.");
        }

        questionCountLabel.setText(String.valueOf(questions.size()));
    }

    private void renderCurrentQuestion() {
        if (questions.isEmpty()) {
            return;
        }

        Question question = questions.get(currentQuestionIndex);
        questionNavLabel.setText("Question " + (currentQuestionIndex + 1) + " sur " + questions.size());
        liveScoreLabel.setText("Score: " + computeScore() + " / " + questions.size());
        answeredCounterLabel.setText(selectedAnswerByQuestionId.size() + " / " + questions.size() + " repondues");
        double progress = questions.isEmpty() ? 0.0 : (currentQuestionIndex + 1) / (double) questions.size();
        questionProgressBar.setProgress(progress);
        questionTextLabel.setText(question.getContent() == null ? "Sans contenu" : question.getContent());

        answersContainer.getChildren().clear();
        Integer selectedId = selectedAnswerByQuestionId.get(question.getId());

        List<Answer> questionAnswers = answers.stream()
                .filter(answer -> answer.getQuestion() != null && Objects.equals(answer.getQuestion().getId(), question.getId()))
                .toList();

        for (Answer answer : questionAnswers) {
            Button answerButton = new Button(answer.getContent() == null ? "Sans contenu" : answer.getContent());
            answerButton.getStyleClass().setAll("quiz-answer-option");
            answerButton.setMaxWidth(Double.MAX_VALUE);
            if (selectedId != null && Objects.equals(selectedId, answer.getId())) {
                answerButton.getStyleClass().add("selected");
            }
            answerButton.setOnAction(evt -> onAnswerSelected(question, answer));
            answersContainer.getChildren().add(answerButton);
        }

        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }

        renderQuickNav();
        prevButton.setDisable(currentQuestionIndex == 0);
        nextButton.setDisable(currentQuestionIndex >= questions.size() - 1);
        finishButton.setDisable(false);
    }

    private void renderQuickNav() {
        quickNavContainer.getChildren().clear();
        for (int i = 0; i < questions.size(); i++) {
            Question q = questions.get(i);
            Button navButton = new Button(String.valueOf(i + 1));
            navButton.getStyleClass().setAll("page-btn");
            if (i == currentQuestionIndex) {
                navButton.getStyleClass().add("active-pill");
            } else if (selectedAnswerByQuestionId.containsKey(q.getId())) {
                navButton.getStyleClass().add("duration-pill");
            }
            final int idx = i;
            navButton.setOnAction(evt -> {
                currentQuestionIndex = idx;
                renderCurrentQuestion();
            });
            quickNavContainer.getChildren().add(navButton);
        }
    }

    private void onAnswerSelected(Question question, Answer answer) {
        selectedAnswerByQuestionId.put(question.getId(), answer.getId());
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
        renderCurrentQuestion();
    }

    private int computeScore() {
        int score = 0;
        for (Question question : questions) {
            Integer selected = selectedAnswerByQuestionId.get(question.getId());
            if (selected == null) {
                continue;
            }
            boolean isCorrect = answers.stream()
                    .anyMatch(answer -> answer.getQuestion() != null
                            && Objects.equals(answer.getQuestion().getId(), question.getId())
                            && answer.isCorrect()
                            && Objects.equals(answer.getId(), selected));
            if (isCorrect) {
                score++;
            }
        }
        return score;
    }

    private void showSection(boolean introVisible, boolean questionVisible, boolean resultVisible) {
        introSection.setVisible(introVisible);
        introSection.setManaged(introVisible);

        questionSection.setVisible(questionVisible);
        questionSection.setManaged(questionVisible);

        resultSection.setVisible(resultVisible);
        resultSection.setManaged(resultVisible);
    }

    private void showError(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.ERROR, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    private void showWarning(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.WARNING, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    @FXML
    private void onTranslate() {
        if (questions.isEmpty()) {
            showWarning("Traduction", "Aucune question disponible pour la traduction.");
            return;
        }

        isTranslatedFr = !isTranslatedFr;
        String targetLang = isTranslatedFr ? "fr" : "en";

        // Désactiver le bouton de traduction temporairement
        Button translateBtn = findTranslateButton();
        if (translateBtn != null) {
            translateBtn.setDisable(true);
            translateBtn.setText("⏳ Traduction en cours...");
        }

        // Lancer la traduction dans un thread séparé avec un timeout
        CompletableFuture.runAsync(() -> {
            try {
                System.out.println("[QuizSessionController] Début de la traduction vers " + targetLang);

                // Traduire les questions
                for (int i = 0; i < questions.size(); i++) {
                    Question q = questions.get(i);
                    if (q.getContent() != null && !q.getContent().isBlank()) {
                        System.out.println("[QuizSessionController] Traduction question " + (i+1) + "/" + questions.size());
                        String translated = translationService.translate(q.getContent(), targetLang);
                        q.setContent(translated);
                    }
                }

                // Traduire les réponses
                for (int i = 0; i < answers.size(); i++) {
                    Answer a = answers.get(i);
                    if (a.getContent() != null && !a.getContent().isBlank()) {
                        if (i % 10 == 0) {
                            System.out.println("[QuizSessionController] Traduction réponse " + (i+1) + "/" + answers.size());
                        }
                        String translated = translationService.translate(a.getContent(), targetLang);
                        a.setContent(translated);
                    }
                }

                System.out.println("[QuizSessionController] Traduction terminée avec succès");

                // Mettre à jour l'UI sur le thread JavaFX
                Platform.runLater(() -> {
                    if (translateBtn != null) {
                        translateBtn.setDisable(false);
                        translateBtn.setText(isTranslatedFr ? " En Français" : " En Anglais");
                    }

                    if (questionSection.isVisible()) {
                        renderCurrentQuestion();
                    }

                    showInfo("Traduction", "Traduction réussie en " + (isTranslatedFr ? "français" : "anglais"));
                });

            } catch (Exception e) {
                System.err.println("[QuizSessionController] Erreur lors de la traduction: " + e.getMessage());
                e.printStackTrace();

                // Restaurer l'état en cas d'erreur
                Platform.runLater(() -> {
                    isTranslatedFr = !isTranslatedFr; // Inverser pour revenir à l'état initial
                    if (translateBtn != null) {
                        translateBtn.setDisable(false);
                        translateBtn.setText(" Traduire");
                    }
                    showError("Traduction", "Erreur lors de la traduction: " + e.getMessage());
                });
            }
        });
    }

    /**
     * Trouve le bouton de traduction dans le FXML
     */
    private Button findTranslateButton() {
        if (quizTitleLabel == null || quizTitleLabel.getScene() == null) {
            return null;
        }

        // Chercher le bouton avec le texte contenant le globe
        for (Node node : quizTitleLabel.getScene().getRoot().lookupAll("Button")) {
            if (node instanceof Button) {
                Button btn = (Button) node;
                if (btn.getText() != null && btn.getText().contains("")) {
                    return btn;
                }
            }
        }

        return null;
    }

    private void showInfo(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }
}

package com.pidev.Controllers.client;

import com.pidev.Services.AnswerService;
import com.pidev.Services.QuestionService;
import com.pidev.Services.QuizStatisticsService;
import com.pidev.models.Answer;
import com.pidev.models.Question;
import com.pidev.models.Quiz;
import javafx.fxml.FXML;
import javafx.geometry.Pos;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.ProgressBar;
import javafx.scene.layout.HBox;
import javafx.scene.layout.Priority;
import javafx.scene.layout.Region;
import javafx.scene.layout.VBox;
import javafx.animation.KeyFrame;
import javafx.animation.Timeline;
import javafx.util.Duration;
import javafx.stage.Window;
import javafx.application.Platform;
import javafx.scene.Node;
import java.util.concurrent.CompletableFuture;
import com.pidev.Services.AiFeedbackService;
import com.pidev.Services.TranslationService;
import com.pidev.Services.CertificateGeneratorService;
import javafx.stage.FileChooser;
import java.io.File;
import java.awt.Desktop;

import java.sql.SQLException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;

public class QuizSessionController {

    @FXML private Label quizTitleLabel;
    @FXML private Label quizContextLabel;
    @FXML private Label questionCountLabel;
    @FXML private Label attemptLabel;
    @FXML private Label requiredScoreLabel;
    @FXML private Label timeLimitLabel;

    @FXML private VBox introSection;
    @FXML private VBox questionSection;
    @FXML private VBox resultSection;

    @FXML private Label questionNavLabel;
    @FXML private Label answeredCounterLabel;
    @FXML private Label liveScoreLabel;
    @FXML private ProgressBar questionProgressBar;
    @FXML private Label timerBadgeLabel;
    @FXML private Label questionTextLabel;
    @FXML private Label questionFeedbackLabel;
    @FXML private VBox answersContainer;
    @FXML private HBox quickNavContainer;

    @FXML private Button prevButton;
    @FXML private Button nextButton;
    @FXML private Button finishButton;

    @FXML private Label resultTitleLabel;
    @FXML private Label resultSummaryLabel;
    @FXML private Label resultScoreLabel;
    @FXML private Label aiFeedbackLabel;
    @FXML private Button downloadCertButton;

    private final QuestionService questionService = new QuestionService();
    private final AnswerService answerService = new AnswerService();
    private final QuizStatisticsService quizStatisticsService = new QuizStatisticsService();
    private final AiFeedbackService aiFeedbackService = new AiFeedbackService();
    private final TranslationService translationService = new TranslationService();
    private final CertificateGeneratorService certificateGeneratorService = new CertificateGeneratorService();

    private final Map<Integer, Integer> selectedAnswerByQuestionId = new HashMap<>();
    private List<Question> questions = new ArrayList<>();
    private List<Answer> answers = new ArrayList<>();

    private Quiz quiz;
    private int currentQuestionIndex;
    private int remainingSeconds;
    private Timeline countdownTimeline;
    private Timeline flashTimeline;       // NOUVEAU : Timeline dédiée au clignotement
    private boolean flashVisible = true;  // NOUVEAU : état du clignotement
    private boolean isTranslatedFr = false;

    @FXML
    public void initialize() {
        showSection(true, false, false);
        timerBadgeLabel.setText("Libre");
        if (answeredCounterLabel != null) {
            answeredCounterLabel.setText("0 / 0 repondues");
        }
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
    }

    public void setQuizContext(Quiz quiz, String chapterName) {
        this.quiz = quiz;
        String title = quiz != null && quiz.getTitle() != null ? quiz.getTitle() : "Quiz";
        quizTitleLabel.setText(title);
        quizContextLabel.setText(chapterName == null || chapterName.isBlank() ? "Quiz du cours" : chapterName);

        int attempts = quiz != null && quiz.getMaxAttempts() > 0 ? quiz.getMaxAttempts() : 3;
        int passing = quiz != null ? Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore()) : 70;
        int time = quiz != null ? quiz.getTimeLimit() : 0;

        attemptLabel.setText("1/" + attempts);
        requiredScoreLabel.setText(passing + "%");
        timeLimitLabel.setText(time <= 0 ? "Libre" : time + " min");
        remainingSeconds = Math.max(0, time) * 60;
        timerBadgeLabel.setText(time <= 0 ? "Libre" : formatTime(remainingSeconds));

        loadQuizData();
    }

    @FXML
    private void onStartQuiz() {
        if (questions.isEmpty()) {
            showError("Quiz", "Aucune question disponible pour ce quiz.");
            return;
        }
        selectedAnswerByQuestionId.clear();
        currentQuestionIndex = 0;
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
        startCountdown();
        showSection(false, true, false);
        renderCurrentQuestion();
    }

    @FXML
    private void onPrevQuestion() {
        if (currentQuestionIndex > 0) {
            currentQuestionIndex--;
            renderCurrentQuestion();
        }
    }

    @FXML
    private void onNextQuestion() {
        if (currentQuestionIndex < questions.size() - 1) {
            currentQuestionIndex++;
            renderCurrentQuestion();
        }
    }

    @FXML
    private void onFinishQuiz() {
        if (questions.isEmpty()) {
            return;
        }

        int unanswered = questions.size() - selectedAnswerByQuestionId.size();
        if (unanswered > 0) {
            Alert confirm = new Alert(Alert.AlertType.CONFIRMATION);
            confirm.setTitle("Soumettre le quiz");
            confirm.setHeaderText("Questions non repondues: " + unanswered);
            confirm.setContentText("Voulez-vous terminer le quiz maintenant ? Les questions non repondues seront comptees comme incorrectes.");
            if (confirm.showAndWait().isEmpty() || confirm.getResult().getButtonData().isCancelButton()) {
                return;
            }
        }

        stopCountdown();

        int total = questions.size();
        int score = computeScore();
        int percent = total == 0 ? 0 : Math.round(score * 100f / total);
        int passing = Math.round(quiz.getPassingScore() <= 0 ? 70f : quiz.getPassingScore());
        boolean passed = percent >= passing;
        int attemptNumber = 1;

        try {
            attemptNumber = quizStatisticsService.saveQuizAttempt(quiz.getId(), null, percent);
        } catch (SQLException e) {
            showError("Sauvegarde quiz", "Tentative non enregistree en base: " + e.getMessage());
        }

        resultTitleLabel.setText(passed ? "Quiz valide" : "Quiz non valide");
        resultSummaryLabel.setText(
                passed
                        ? "Bravo, vous avez atteint le score requis. Tentative " + attemptNumber + "."
                        : "Vous pouvez relancer le quiz pour améliorer votre resultat. Tentative " + attemptNumber + "."
        );
        resultScoreLabel.setText(score + " / " + total + " (" + percent + "%)");
        resultScoreLabel.getStyleClass().setAll("result-score-badge", passed ? "success" : "fail");

        if (!passed) {
            List<Question> failedQuestions = questions.stream()
                .filter(q -> {
                    Integer sel = selectedAnswerByQuestionId.get(q.getId());
                    return sel == null || answers.stream().noneMatch(a -> a.getQuestion() != null && Objects.equals(a.getQuestion().getId(), q.getId()) && a.isCorrect() && Objects.equals(a.getId(), sel));
                })
                .toList();
            String feedback = aiFeedbackService.generateFeedback(failedQuestions);
            aiFeedbackLabel.setText(feedback);
            aiFeedbackLabel.setVisible(true);
            aiFeedbackLabel.setManaged(true);
            if (downloadCertButton != null) {
                downloadCertButton.setVisible(false);
                downloadCertButton.setManaged(false);
            }
        } else {
            aiFeedbackLabel.setVisible(false);
            aiFeedbackLabel.setManaged(false);
            if (downloadCertButton != null) {
                downloadCertButton.setVisible(true);
                downloadCertButton.setManaged(true);
            }
        }

        showSection(false, false, true);
    }

    @FXML
    private void onCloseWindow() {
        Window window = quizTitleLabel.getScene() != null ? quizTitleLabel.getScene().getWindow() : null;
        if (window != null) {
            window.hide();
        }
    }

    @FXML
    private void onRetry() {
        onStartQuiz();
    }

    @FXML
    private void onDownloadCertificate() {
        FileChooser fileChooser = new FileChooser();
        fileChooser.setTitle("Enregistrer le certificat");
        fileChooser.getExtensionFilters().add(new FileChooser.ExtensionFilter("Fichiers PDF", "*.pdf"));
        fileChooser.setInitialFileName("Certificat_" + (quiz != null && quiz.getTitle() != null ? quiz.getTitle().replaceAll("\\s+", "_") : "Quiz") + ".pdf");
        Window window = quizTitleLabel.getScene() != null ? quizTitleLabel.getScene().getWindow() : null;
        if (window == null) return;
        File file = fileChooser.showSaveDialog(window);

        if (file != null) {
            try {
                int total = questions.size();
                int score = computeScore();
                int percent = total == 0 ? 0 : Math.round(score * 100f / total);
                String courseName = quizContextLabel.getText();
                certificateGeneratorService.generateCertificate(file.getAbsolutePath(), "Étudiant", courseName, percent);

                Alert success = new Alert(Alert.AlertType.INFORMATION);
                success.setTitle("Succès");
                success.setHeaderText("Certificat généré avec succès !");
                success.setContentText("Le certificat a été sauvegardé dans : " + file.getAbsolutePath());
                success.showAndWait();

                try {
                    Desktop.getDesktop().open(file);
                } catch (Exception e) {
                    // Ignorer
                }
            } catch (Exception e) {
                showError("Erreur", "Impossible de générer le certificat : " + e.getMessage());
            }
        }
    }

    private void startCountdown() {
        stopCountdown();
        int timeLimitMinutes = quiz == null ? 0 : quiz.getTimeLimit();
        if (timeLimitMinutes <= 0) {
            timerBadgeLabel.setText("Libre");
            timerBadgeLabel.getStyleClass().setAll("timer-normal");
            return;
        }

        remainingSeconds = timeLimitMinutes * 60;
        updateTimerDisplay();

        countdownTimeline = new Timeline(new KeyFrame(Duration.seconds(1), event -> {
            remainingSeconds--;
            updateTimerDisplay();
            if (remainingSeconds <= 0) {
                stopCountdown();
                Platform.runLater(this::onFinishQuiz);
            }
        }));
        countdownTimeline.setCycleCount(Timeline.INDEFINITE);
        countdownTimeline.play();
    }

    private void stopCountdown() {
        if (countdownTimeline != null) {
            countdownTimeline.stop();
            countdownTimeline = null;
        }
        stopFlashAnimation();
        // Réinitialiser le style du timer
        timerBadgeLabel.getStyleClass().setAll("timer-normal");
        timerBadgeLabel.setOpacity(1.0);
    }

    private String formatTime(int seconds) {
        int safeSeconds = Math.max(0, seconds);
        int minutes = safeSeconds / 60;
        int rest = safeSeconds % 60;
        return String.format("%02d:%02d", minutes, rest);
    }

    private void updateTimerDisplay() {
        int safeSeconds = Math.max(0, remainingSeconds);
        timerBadgeLabel.setText(formatTime(safeSeconds));

        if (safeSeconds <= 0) {
            // Temps écoulé
            timerBadgeLabel.getStyleClass().setAll("flash-animation");
            timerBadgeLabel.setStyle("-fx-text-fill: #dc2626;");
            return;
        }

        if (safeSeconds <= 10) {
            // 10 dernières secondes : clignotement rouge rapide (via Timeline)
            timerBadgeLabel.getStyleClass().setAll("flash-animation");
            timerBadgeLabel.setOpacity(1.0); // opacity gérée par flashTimeline
            startFlashAnimation();

        } else if (safeSeconds <= 30) {
            // 30 → 11 secondes : pulse orange (style uniquement, pas de clignotement)
            stopFlashAnimation();
            timerBadgeLabel.setOpacity(1.0);
            timerBadgeLabel.getStyleClass().setAll("pulse-animation");
            timerBadgeLabel.setStyle(""); // Laisser le CSS prendre le relais

        } else if (safeSeconds <= 120) {
            // 2 minutes → 31 secondes : rouge texte, pas d'animation
            stopFlashAnimation();
            timerBadgeLabel.setOpacity(1.0);
            timerBadgeLabel.getStyleClass().setAll("timer-normal");
            timerBadgeLabel.setStyle("-fx-text-fill: #dc2626;");

        } else {
            // Temps normal
            stopFlashAnimation();
            timerBadgeLabel.setOpacity(1.0);
            timerBadgeLabel.getStyleClass().setAll("timer-normal");
            timerBadgeLabel.setStyle("-fx-text-fill: #1f2937;");
        }
    }

    private void startFlashAnimation() {
        if (flashTimeline != null && flashTimeline.getStatus() == javafx.animation.Animation.Status.RUNNING) {
            return; // Déjà en cours
        }

        flashVisible = true;
        // Clignote toutes les 400ms (rouge vif ↔ quasi invisible)
        flashTimeline = new Timeline(
            new KeyFrame(Duration.millis(400), event -> {
                flashVisible = !flashVisible;
                timerBadgeLabel.setOpacity(flashVisible ? 1.0 : 0.15);
            })
        );
        flashTimeline.setCycleCount(Timeline.INDEFINITE);
        flashTimeline.play();
    }

    private void stopFlashAnimation() {
        if (flashTimeline != null) {
            flashTimeline.stop();
            flashTimeline = null;
        }
        timerBadgeLabel.setOpacity(1.0);
    }

    private void loadQuizData() {
        try {
            List<Question> loadedQuestions = questionService.findAll().stream()
                    .filter(item -> item.getQuiz() != null && quiz != null && Objects.equals(item.getQuiz().getId(), quiz.getId()))
                    .sorted(Comparator.comparingInt(item -> item.getId() == null ? Integer.MAX_VALUE : item.getId()))
                    .toList();
            this.questions = new ArrayList<>(loadedQuestions);
            this.answers = answerService.findAll();
        } catch (SQLException e) {
            this.questions = new ArrayList<>();
            this.answers = new ArrayList<>();
            showError("Quiz", "Impossible de charger les questions du quiz.");
        }

        questionCountLabel.setText(String.valueOf(questions.size()));
    }

    private void renderCurrentQuestion() {
        if (questions.isEmpty()) {
            return;
        }

        Question question = questions.get(currentQuestionIndex);
        questionNavLabel.setText("Question " + (currentQuestionIndex + 1) + " sur " + questions.size());
        liveScoreLabel.setText("Score: " + computeScore() + " / " + questions.size());
        answeredCounterLabel.setText(selectedAnswerByQuestionId.size() + " / " + questions.size() + " repondues");
        double progress = questions.isEmpty() ? 0.0 : (currentQuestionIndex + 1) / (double) questions.size();
        questionProgressBar.setProgress(progress);
        questionTextLabel.setText(question.getContent() == null ? "Sans contenu" : question.getContent());

        answersContainer.getChildren().clear();
        Integer selectedId = selectedAnswerByQuestionId.get(question.getId());

        List<Answer> questionAnswers = answers.stream()
                .filter(answer -> answer.getQuestion() != null && Objects.equals(answer.getQuestion().getId(), question.getId()))
                .toList();

        for (Answer answer : questionAnswers) {
            Button answerButton = new Button(answer.getContent() == null ? "Sans contenu" : answer.getContent());
            answerButton.getStyleClass().setAll("quiz-answer-option");
            answerButton.setMaxWidth(Double.MAX_VALUE);
            if (selectedId != null && Objects.equals(selectedId, answer.getId())) {
                answerButton.getStyleClass().add("selected");
            }
            answerButton.setOnAction(evt -> onAnswerSelected(question, answer));
            answersContainer.getChildren().add(answerButton);
        }

        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }

        renderQuickNav();
        prevButton.setDisable(currentQuestionIndex == 0);
        nextButton.setDisable(currentQuestionIndex >= questions.size() - 1);
        finishButton.setDisable(false);
    }

    private void renderQuickNav() {
        quickNavContainer.getChildren().clear();
        for (int i = 0; i < questions.size(); i++) {
            Question q = questions.get(i);
            Button navButton = new Button(String.valueOf(i + 1));
            navButton.getStyleClass().setAll("page-btn");
            if (i == currentQuestionIndex) {
                navButton.getStyleClass().add("active-pill");
            } else if (selectedAnswerByQuestionId.containsKey(q.getId())) {
                navButton.getStyleClass().add("duration-pill");
            }
            final int idx = i;
            navButton.setOnAction(evt -> {
                currentQuestionIndex = idx;
                renderCurrentQuestion();
            });
            quickNavContainer.getChildren().add(navButton);
        }
    }

    private void onAnswerSelected(Question question, Answer answer) {
        selectedAnswerByQuestionId.put(question.getId(), answer.getId());
        if (questionFeedbackLabel != null) {
            questionFeedbackLabel.setText("");
        }
        renderCurrentQuestion();
    }

    private int computeScore() {
        int score = 0;
        for (Question question : questions) {
            Integer selected = selectedAnswerByQuestionId.get(question.getId());
            if (selected == null) {
                continue;
            }
            boolean isCorrect = answers.stream()
                    .anyMatch(answer -> answer.getQuestion() != null
                            && Objects.equals(answer.getQuestion().getId(), question.getId())
                            && answer.isCorrect()
                            && Objects.equals(answer.getId(), selected));
            if (isCorrect) {
                score++;
            }
        }
        return score;
    }

    private void showSection(boolean introVisible, boolean questionVisible, boolean resultVisible) {
        introSection.setVisible(introVisible);
        introSection.setManaged(introVisible);

        questionSection.setVisible(questionVisible);
        questionSection.setManaged(questionVisible);

        resultSection.setVisible(resultVisible);
        resultSection.setManaged(resultVisible);
    }

    private void showError(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.ERROR, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    private void showWarning(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.WARNING, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }

    @FXML
    private void onTranslate() {
        if (questions.isEmpty()) {
            showWarning("Traduction", "Aucune question disponible pour la traduction.");
            return;
        }

        isTranslatedFr = !isTranslatedFr;
        String targetLang = isTranslatedFr ? "fr" : "en";

        // Désactiver le bouton de traduction temporairement
        Button translateBtn = findTranslateButton();
        if (translateBtn != null) {
            translateBtn.setDisable(true);
            translateBtn.setText("⏳ Traduction en cours...");
        }

        // Lancer la traduction dans un thread séparé avec un timeout
        CompletableFuture.runAsync(() -> {
            try {
                System.out.println("[QuizSessionController] Début de la traduction vers " + targetLang);

                // Traduire les questions
                for (int i = 0; i < questions.size(); i++) {
                    Question q = questions.get(i);
                    if (q.getContent() != null && !q.getContent().isBlank()) {
                        System.out.println("[QuizSessionController] Traduction question " + (i+1) + "/" + questions.size());
                        String translated = translationService.translate(q.getContent(), targetLang);
                        q.setContent(translated);
                    }
                }

                // Traduire les réponses
                for (int i = 0; i < answers.size(); i++) {
                    Answer a = answers.get(i);
                    if (a.getContent() != null && !a.getContent().isBlank()) {
                        if (i % 10 == 0) {
                            System.out.println("[QuizSessionController] Traduction réponse " + (i+1) + "/" + answers.size());
                        }
                        String translated = translationService.translate(a.getContent(), targetLang);
                        a.setContent(translated);
                    }
                }

                System.out.println("[QuizSessionController] Traduction terminée avec succès");

                // Mettre à jour l'UI sur le thread JavaFX
                Platform.runLater(() -> {
                    if (translateBtn != null) {
                        translateBtn.setDisable(false);
                        translateBtn.setText(isTranslatedFr ? " En Français" : " En Anglais");
                    }

                    if (questionSection.isVisible()) {
                        renderCurrentQuestion();
                    }

                    showInfo("Traduction", "Traduction réussie en " + (isTranslatedFr ? "français" : "anglais"));
                });

            } catch (Exception e) {
                System.err.println("[QuizSessionController] Erreur lors de la traduction: " + e.getMessage());
                e.printStackTrace();

                // Restaurer l'état en cas d'erreur
                Platform.runLater(() -> {
                    isTranslatedFr = !isTranslatedFr; // Inverser pour revenir à l'état initial
                    if (translateBtn != null) {
                        translateBtn.setDisable(false);
                        translateBtn.setText(" Traduire");
                    }
                    showError("Traduction", "Erreur lors de la traduction: " + e.getMessage());
                });
            }
        });
    }

    /**
     * Trouve le bouton de traduction dans le FXML
     */
    private Button findTranslateButton() {
        if (quizTitleLabel == null || quizTitleLabel.getScene() == null) {
            return null;
        }

        // Chercher le bouton avec le texte contenant le globe
        for (Node node : quizTitleLabel.getScene().getRoot().lookupAll("Button")) {
            if (node instanceof Button) {
                Button btn = (Button) node;
                if (btn.getText() != null && btn.getText().contains("")) {
                    return btn;
                }
            }
        }

        return null;
    }

    private void showInfo(String title, String message) {
        Alert alert = new Alert(Alert.AlertType.INFORMATION, message);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.showAndWait();
    }
}

package com.pidev.Services;

import org.apache.pdfbox.pdmodel.PDDocument;
import org.apache.pdfbox.text.PDFTextStripper;
import org.json.JSONArray;
import org.json.JSONObject;

import java.io.File;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.ArrayList;
import java.util.List;

/**
 * Service gérant la génération de Quiz via l'Intelligence Artificielle (Gemini API)
 * à partir d'un fichier de cours au format PDF.
 */
public class GeminiQuizService {

    // API v1 stable + gemini-1.5-flash (modèle rapide, supporté par toutes les clés AI Studio)
    private static final String GEMINI_API_URL = "https://generativelanguage.googleapis.com/v1/models/gemini-1.5-flash:generateContent?key=";

    /**
     * 1. Extrait le texte brut d'un fichier PDF donné.
     * 
     * @param pdfFile Le fichier PDF importé par le professeur.
     * @return Le texte contenu dans le PDF.
     */
    public String extractTextFromPdf(File pdfFile) throws IOException {
        try (PDDocument document = PDDocument.load(pdfFile)) {
            PDFTextStripper pdfStripper = new PDFTextStripper();
            return pdfStripper.getText(document);
        }
    }

    /**
     * 2. Envoie le texte du PDF à Gemini pour générer un Quiz structuré (JSON).
     * 
     * @param pdfFile Le fichier PDF du cours.
     * @param apiKey  La clé d'API Google Gemini.
     * @param nbQuestions Le nombre de questions à générer.
     * @return Une chaîne de caractères JSON contenant les questions générées.
     */
    public String generateQuiz(File pdfFile, String apiKey, int nbQuestions) throws Exception {
        // --- Étape 1 : Extraction du texte ---
        String pdfText = extractTextFromPdf(pdfFile);

        // Sécurité : limiter la taille du texte pour ne pas dépasser les tokens max de l'API
        // 100 000 caractères représentent un très gros document.
        if (pdfText.length() > 100000) {
            pdfText = pdfText.substring(0, 100000);
        }

        // --- Étape 2 : Construction du Prompt pour l'IA ---
        String prompt = "Tu es un professeur expert. Génère un quiz pertinent de " + nbQuestions + " questions à choix multiples basé STRICTEMENT sur le cours suivant.\n\n" +
                "--- DEBUT DU COURS ---\n" +
                pdfText + "\n" +
                "--- FIN DU COURS ---\n\n" +
                "Règles :\n" +
                "- Chaque question doit avoir 4 options.\n" +
                "- L'index de la bonne réponse doit être 0, 1, 2 ou 3.\n" +
                "- Renvoie UNIQUEMENT un tableau JSON valide. Pas de markdown (```json ... ```), juste le JSON brut.\n" +
                "\nFormat attendu :\n" +
                "[\n" +
                "  {\n" +
                "    \"question\": \"Le texte de la question ?\",\n" +
                "    \"options\": [\"Choix A\", \"Choix B\", \"Choix C\", \"Choix D\"],\n" +
                "    \"correctAnswerIndex\": 2,\n" +
                "    \"explanation\": \"Explication de la réponse\"\n" +
                "  }\n" +
                "]";

        // --- Étape 3 : Création du payload (Body HTTP) ---
        JSONObject requestBody = new JSONObject();
        JSONArray contents = new JSONArray();
        JSONObject content = new JSONObject();
        JSONArray parts = new JSONArray();
        JSONObject part = new JSONObject();

        part.put("text", prompt);
        parts.put(part);
        content.put("parts", parts);
        contents.put(content);
        requestBody.put("contents", contents);

        // Note: La contrainte de format JSON strict est gérée par le prompt lui-même
        // car la propriété 'response_mime_type' n'est pas toujours supportée par la version gemini-pro.

        // --- Étape 4 : Appel HTTP à l'API Gemini ---
        HttpClient client = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(30))
                .build();

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(GEMINI_API_URL + apiKey))
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(requestBody.toString()))
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

        // --- Étape 5 : Traitement de la réponse ---
        if (response.statusCode() == 200) {
            JSONObject jsonResponse = new JSONObject(response.body());
            JSONArray candidates = jsonResponse.getJSONArray("candidates");
            if (candidates.length() > 0) {
                JSONObject firstCandidate = candidates.getJSONObject(0);
                JSONObject candidateContent = firstCandidate.getJSONObject("content");
                JSONArray candidateParts = candidateContent.getJSONArray("parts");
                if (candidateParts.length() > 0) {
                    // C'est ici qu'on récupère le JSON brut généré par l'IA
                    String generatedJson = candidateParts.getJSONObject(0).getString("text").trim();

                    // Nettoyage au cas où Gemini ajoute des balises Markdown (très fréquent avec gemini-pro)
                    if (generatedJson.startsWith("```json")) {
                        generatedJson = generatedJson.substring(7);
                    } else if (generatedJson.startsWith("```")) {
                        generatedJson = generatedJson.substring(3);
                    }
                    if (generatedJson.endsWith("```")) {
                        generatedJson = generatedJson.substring(0, generatedJson.length() - 3);
                    }

                    return generatedJson.trim(); 
                }
            }
            throw new Exception("Format de réponse inattendu de l'API Gemini.");
        } else {
            throw new Exception("Erreur API Gemini (Code " + response.statusCode() + ") : " + response.body());
        }
    }
}

